<script setup lang="ts">
import { nextTick,onBeforeUnmount,onMounted,ref } from 'vue'
import { ElMessage } from 'element-plus'
import { Connection,Promotion,Refresh,Search } from '@element-plus/icons-vue'
import { GraphChart } from 'echarts/charts'
import { LegendComponent,TooltipComponent } from 'echarts/components'
import { init,use,type ECharts } from 'echarts/core'
import { CanvasRenderer } from 'echarts/renderers'
import { listDocuments,type GeologicalDocument } from '@/api/documents'
import { askGeologicalQuestion,expandGraphNode,getGraphStatus,queryGraphNodes,queryGraphPath,syncGraph,type GraphNode,type GraphStatus,type GraphView,type QaResponse } from '@/api/graph'

const documents=ref<GeologicalDocument[]>([]),documentId=ref<number>(),status=ref<GraphStatus>(),graph=ref<GraphView>({nodes:[],links:[]}),query=ref(''),loading=ref(true),syncing=ref(false),selected=ref<GraphNode>(),depth=ref(1),sourceId=ref<number>(),targetId=ref<number>()
const question=ref('鄂东南地区矿体主要受哪些构造控制？'),provider=ref<'deepseek'|'qwen'>('deepseek'),asking=ref(false),answer=ref<QaResponse>()
use([GraphChart,LegendComponent,TooltipComponent,CanvasRenderer])
const graphCanvas=ref<HTMLElement>();let chart:ECharts|undefined,pollTimer:number|undefined
const typeMeta={STRATUM:['地层','#4f7f67'],ROCK_BODY:['岩体','#a86f3d'],STRUCTURE:['构造','#b34f42'],ORE_BODY:['矿体','#d18432'],MINERAL:['矿种','#3f7d82'],REGION:['地区','#745d92']} as const
const relationLabel:Record<string,string>={LOCATED_IN:'位于',CONTAINS:'包含',CONTROLS:'控制',INTRUDES:'侵入'}

async function load(){loading.value=true;try{const page=await listDocuments({page:1,size:100,status:'PARSED'});documents.value=page.records.filter(d=>d.spatialStatus==='COMPLETED');documentId.value=documents.value[0]?.id;if(documentId.value)status.value=await getGraphStatus(documentId.value);await searchNodes()}catch(e){ElMessage.error(message(e))}finally{loading.value=false}}
async function changeDocument(){if(documentId.value)status.value=await getGraphStatus(documentId.value)}
async function startSync(){if(!documentId.value)return;syncing.value=true;try{status.value=await syncGraph(documentId.value);schedulePoll();ElMessage.success('图谱与向量索引任务已提交')}catch(e){ElMessage.error(message(e))}finally{syncing.value=false}}
function schedulePoll(){if(pollTimer)clearTimeout(pollTimer);pollTimer=window.setTimeout(poll,1500)}
async function poll(){if(!documentId.value)return;try{status.value=await getGraphStatus(documentId.value);if(status.value.status==='SYNCING')return schedulePoll();if(status.value.status==='COMPLETED'){await searchNodes();ElMessage.success('知识图谱同步完成')}}catch(e){ElMessage.error(message(e))}}
async function searchNodes(){try{graph.value=await queryGraphNodes(query.value);selected.value=undefined;render()}catch(e){if(query.value)ElMessage.error(message(e))}}
async function expand(node:GraphNode){try{selected.value=node;graph.value=await expandGraphNode(node.id,depth.value);render()}catch(e){ElMessage.error(message(e))}}
async function findPath(){if(!sourceId.value||!targetId.value)return ElMessage.warning('请选择起点和终点');try{graph.value=await queryGraphPath(sourceId.value,targetId.value);render()}catch(e){ElMessage.error(message(e))}}
async function ask(){if(!question.value.trim())return;asking.value=true;answer.value=undefined;try{answer.value=await askGeologicalQuestion(question.value,provider.value)}catch(e){ElMessage.error(message(e))}finally{asking.value=false}}
function render(){nextTick(()=>{if(!graphCanvas.value)return;if(!chart){chart=init(graphCanvas.value);chart.on('click',params=>{if(params.dataType==='node'){const node=graph.value.nodes.find(item=>item.id===Number((params.data as {id:string}).id));if(node)expand(node)}})}const categories=Object.values(typeMeta).map(([label])=>({name:label}));chart.setOption({backgroundColor:'transparent',tooltip:{trigger:'item'},legend:[{data:Object.values(typeMeta).map(v=>v[0]),bottom:8,textStyle:{color:'#dbe4dc'}}],series:[{type:'graph',layout:'force',roam:true,draggable:true,categories,data:graph.value.nodes.map(n=>({id:String(n.id),name:n.name,value:n.nodeType,category:Object.keys(typeMeta).indexOf(n.nodeType),symbolSize:selected.value?.id===n.id?48:34,itemStyle:{color:typeMeta[n.nodeType][1],borderColor:'#f4e8cf',borderWidth:2},label:{show:true,color:'#f8f3e8',position:'right'}})),links:graph.value.links.map(l=>({source:String(l.source),target:String(l.target),value:relationLabel[l.relationType],lineStyle:{color:'#b9aa88',width:2,curveness:.12},label:{show:true,formatter:relationLabel[l.relationType],color:'#d9c9a7',fontSize:10}})),force:{repulsion:260,edgeLength:[90,170],gravity:.08},edgeSymbol:['none','arrow'],edgeSymbolSize:8,emphasis:{focus:'adjacency',lineStyle:{width:4}}}]},true)})}
function resize(){chart?.resize()}function message(e:unknown){return e instanceof Error?e.message:'操作失败'}
onMounted(()=>{window.addEventListener('resize',resize);load()});onBeforeUnmount(()=>{window.removeEventListener('resize',resize);if(pollTimer)clearTimeout(pollTimer);chart?.dispose()})
</script>

<template><div class="graph-page" v-loading="loading"><header class="graph-hero"><div><span>Phase 7 · GRAPH + RETRIEVAL</span><h1>知识网络与证据问答</h1><p>用关系探索地质对象，用原文证据约束每一次回答。</p></div><div class="graph-stats"><b>{{status?.nodeCount||graph.nodes.length}}</b><small>节点</small><b>{{status?.relationCount||graph.links.length}}</b><small>关系</small><b>{{status?.vectorCount||0}}</b><small>向量段落</small></div></header><div class="graph-workbench"><aside class="graph-controls"><section><small>知识来源</small><el-select v-model="documentId" placeholder="选择已空间化资料" @change="changeDocument"><el-option v-for="item in documents" :key="item.id" :label="item.name" :value="item.id"/></el-select><button class="graph-sync" type="button" :disabled="syncing||status?.status==='SYNCING'" @click="startSync"><el-icon><Refresh/></el-icon>{{status?.status==='COMPLETED'?'重新同步':status?.status==='SYNCING'?`同步 ${status.progress}%`:'构建图谱与索引'}}</button><p v-if="status?.errorMessage" class="graph-error">{{status.errorMessage}}</p></section><section><small>节点查询</small><div class="graph-search"><el-input v-model="query" clearable placeholder="地层、岩体、构造…" @keyup.enter="searchNodes"/><button type="button" @click="searchNodes"><el-icon><Search/></el-icon></button></div><label>展开深度 <el-slider v-model="depth" :min="1" :max="3" :step="1" show-stops/></label></section><section><small>路径查询</small><el-select v-model="sourceId" filterable placeholder="起点"><el-option v-for="node in graph.nodes" :key="node.id" :label="node.name" :value="node.id"/></el-select><el-select v-model="targetId" filterable placeholder="终点"><el-option v-for="node in graph.nodes" :key="node.id" :label="node.name" :value="node.id"/></el-select><button type="button" @click="findPath"><el-icon><Connection/></el-icon>查找最短路径</button></section></aside><section class="graph-stage"><div ref="graphCanvas" class="graph-canvas"></div><div v-if="!graph.nodes.length" class="graph-empty"><Connection/><strong>等待图谱数据</strong><p>选择资料并构建 Neo4j 图谱。</p></div><aside v-if="selected" class="node-card"><small>{{typeMeta[selected.nodeType][0]}} · 第 {{selected.page}} 页</small><h2>{{selected.name}}</h2><p>{{selected.sourceText}}</p><span v-if="selected.longitude!=null">{{selected.longitude.toFixed(5)}}, {{selected.latitude?.toFixed(5)}}</span></aside></section></div><section class="qa-lab"><header><div><span>RAG EVIDENCE DESK</span><h2>地质智能问答</h2></div><div class="provider-switch"><button type="button" :class="{active:provider==='deepseek'}" @click="provider='deepseek'">DeepSeek</button><button type="button" :class="{active:provider==='qwen'}" @click="provider='qwen'">Qwen</button></div></header><div class="question-box"><textarea v-model="question" rows="3" placeholder="输入关于地层、构造、矿体或空间关系的问题"></textarea><button type="button" :disabled="asking" @click="ask"><el-icon><Promotion/></el-icon>{{asking?'检索与推理中…':'提交证据问答'}}</button></div><div v-if="answer" class="answer-grid"><article class="answer-main"><small>回答 · {{answer.provider}} / {{answer.model}}</small><p>{{answer.answer}}</p><div><span v-for="entity in answer.relatedEntities" :key="entity.id">{{entity.name}}</span></div><ul><li v-for="location in answer.spatialLocations" :key="location.entityId"><b>{{location.name}}</b>{{location.longitude.toFixed(5)}}, {{location.latitude.toFixed(5)}}</li></ul></article><aside class="answer-sources"><header><strong>来源段落</strong><span>{{answer.sources.length}}</span></header><article v-for="source in answer.sources" :key="source.chunkId"><small>{{source.documentName}} · 第 {{source.pageStart}}–{{source.pageEnd}} 页 · {{Math.round(source.score*100)}}%</small><p>{{source.content}}</p></article></aside></div></section></div></template>

<style scoped>
.graph-page{padding:28px;background:#e9e6dc;min-height:calc(100vh - 82px);color:#173b35}.graph-hero{display:flex;justify-content:space-between;gap:24px;margin-bottom:18px}.graph-hero span,.qa-lab header span{font:700 11px/1.2 ui-monospace;letter-spacing:.18em;color:#b56d30}.graph-hero h1{margin:7px 0 5px;font:600 35px/1.1 Georgia,serif}.graph-hero p{margin:0;color:#66746d}.graph-stats{display:grid;grid-template-columns:repeat(3,auto);gap:3px 18px;align-items:end;text-align:right}.graph-stats b{font:600 25px Georgia;color:#b05e2f}.graph-stats small{grid-row:2;color:#63756c}.graph-workbench{display:grid;grid-template-columns:270px minmax(0,1fr);min-height:620px;background:#123d36;border:1px solid #31584f;box-shadow:0 18px 42px #173a3026}.graph-controls{padding:18px;background:#0c332e;color:#e8e2d1;border-right:1px solid #48645d}.graph-controls section{padding:15px 0;border-bottom:1px solid #ffffff1c;display:grid;gap:10px}.graph-controls small{font:700 10px ui-monospace;letter-spacing:.16em;color:#d79b58}.graph-controls button{border:1px solid #6b887f;background:transparent;color:#f1ead9;padding:10px;cursor:pointer}.graph-controls .graph-sync{background:#e79b50;color:#173b35;border:0;font-weight:700}.graph-search{display:grid;grid-template-columns:1fr 42px}.graph-controls label{font-size:12px;color:#b9c9c2}.graph-stage{position:relative;min-width:0}.graph-canvas{height:620px}.graph-empty{position:absolute;inset:0;display:grid;place-content:center;text-align:center;color:#8fac9f}.graph-empty svg{font-size:42px;margin:auto}.node-card{position:absolute;right:18px;top:18px;width:min(290px,42%);padding:18px;background:#f0eadb;color:#173b35;border-left:4px solid #d98642;box-shadow:0 12px 30px #001c1680}.node-card h2{font:600 24px Georgia;margin:8px 0}.node-card p{font-size:13px;line-height:1.6}.node-card span{font:12px ui-monospace;color:#9b542c}.qa-lab{margin-top:22px;background:#f5f1e8;border:1px solid #cdc5b4;padding:24px}.qa-lab>header{display:flex;justify-content:space-between;align-items:center}.qa-lab h2{font:600 28px Georgia;margin:5px 0 14px}.provider-switch{display:flex;border:1px solid #28554b}.provider-switch button{padding:9px 16px;border:0;background:transparent;color:#28554b}.provider-switch button.active{background:#28554b;color:#fff}.question-box{display:grid;grid-template-columns:1fr 180px;border:1px solid #b9b09f}.question-box textarea{resize:vertical;border:0;background:white;padding:16px;font:15px/1.7 inherit;outline:none}.question-box button{border:0;background:#d98742;color:#fff;font-weight:700}.answer-grid{display:grid;grid-template-columns:minmax(0,1fr) 390px;gap:16px;margin-top:18px}.answer-main,.answer-sources{background:white;border:1px solid #d9d2c4;padding:20px}.answer-main>p{font:18px/1.8 Georgia,serif}.answer-main div{display:flex;flex-wrap:wrap;gap:7px}.answer-main div span{padding:5px 8px;background:#dfe9e4;color:#27564c;font-size:12px}.answer-main ul{padding:0;list-style:none}.answer-main li{display:flex;justify-content:space-between;border-top:1px solid #e4ded1;padding:8px 0;font:12px ui-monospace}.answer-sources{max-height:420px;overflow:auto}.answer-sources header{display:flex;justify-content:space-between}.answer-sources article{border-top:1px solid #ded7ca;padding:12px 0}.answer-sources small{color:#a46032}.answer-sources p{font-size:13px;line-height:1.55;margin:5px 0}.graph-error{color:#ffb0a3;font-size:12px}@media(max-width:900px){.graph-page{padding:14px}.graph-hero{display:block}.graph-stats{justify-content:start;text-align:left;margin-top:12px}.graph-workbench{grid-template-columns:1fr}.graph-controls{border-right:0}.graph-canvas{height:500px}.answer-grid{grid-template-columns:1fr}.question-box{grid-template-columns:1fr}.question-box button{padding:14px}.node-card{width:calc(100% - 36px);top:auto;bottom:18px}.qa-lab{padding:16px}.qa-lab>header{align-items:flex-start;gap:12px}}
</style>
